<?php
namespace App\Domain\Equipment\Data;
final class ItemStatBonuses{private $values;private $criticalHundredths;private $speedHundredths;public function __construct($maxHealth=0,$attack=0,$defense=0,$accuracy=0,$evasion=0,$criticalChance=0,$attackSpeed=0,$absorb=0){$this->criticalHundredths=self::decimalToHundredths($criticalChance);$this->speedHundredths=self::decimalToHundredths($attackSpeed);$absorb=(int)$absorb;if($absorb<0)throw new \InvalidArgumentException('AbsorbDamage cannot be negative.');$this->values=['max_health'=>(int)$maxHealth,'attack'=>(int)$attack,'defense'=>(int)$defense,'accuracy'=>(int)$accuracy,'evasion'=>(int)$evasion,'critical_chance'=>$this->criticalHundredths/100,'attack_speed'=>$this->speedHundredths/100,'absorb_damage_basis_points'=>$absorb];}public static function decimalToHundredths($value){$text=(string)$value;if(!preg_match('/^(0|[1-9][0-9]*)(?:\.([0-9]{1,2}))?$/',$text,$matches))throw new \InvalidArgumentException('Decimal stat bonus must use at most two decimal places.');$whole=$matches[1];$fraction=isset($matches[2])?str_pad($matches[2],2,'0'):'00';if(strlen($whole)>strlen((string)intdiv(PHP_INT_MAX,100)))throw new \InvalidArgumentException('Decimal stat bonus overflow.');$integer=(int)$whole;if($integer>intdiv(PHP_INT_MAX-(int)$fraction,100))throw new \InvalidArgumentException('Decimal stat bonus overflow.');return$integer*100+(int)$fraction;}public static function decimalFromHundredths($value){if(!is_int($value)||$value<0)throw new \InvalidArgumentException('Invalid scaled decimal stat bonus.');return intdiv($value,100).'.'.str_pad((string)($value%100),2,'0',STR_PAD_LEFT);}public function maxHealth(){return$this->values['max_health'];}public function attack(){return$this->values['attack'];}public function defense(){return$this->values['defense'];}public function accuracy(){return$this->values['accuracy'];}public function evasion(){return$this->values['evasion'];}public function criticalChance(){return$this->values['critical_chance'];}public function attackSpeed(){return$this->values['attack_speed'];}public function absorbDamageBasisPoints(){return$this->values['absorb_damage_basis_points'];}public function criticalChanceHundredths(){return$this->criticalHundredths;}public function attackSpeedHundredths(){return$this->speedHundredths;}public function hasAny(){foreach($this->values as$value)if($value!=0)return true;return false;}public function toArray(){return array_merge([],$this->values);}}
